import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-settings.e7FrcLCc.js";const s=JSON.parse(`{"title":"Installare Fabric su macOS","description":"Una guida passo per passo su come installare Fabric su macOS.","frontmatter":{"title":"Installare Fabric su macOS","description":"Una guida passo per passo su come installare Fabric su macOS.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"it_it/players/installing-fabric/macos.md","filePath":"translated/it_it/players/installing-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`it_it/players/installing-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installare Fabric su macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Installare Fabric su macOS”">​</a></h1><div class="info custom-block"><p class="custom-block-title">PREREQUISITI</p><p>Potresti dover <a href="./../installing-java/macos">installare Java</a> prima di eseguire il <code>.jar</code>.</p></div><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Scarica l&#39;Installer di Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Scarica l&#39;Installer di Fabric”">​</a></h2><p>Scarica la versione <code>.jar</code> dell&#39;Installer di Fabric dal <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">sito di Fabric</a>, cliccando su <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Esegui l&#39;Installer di Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Esegui l&#39;Installer di Fabric”">​</a></h2><p>Chiudi Minecraft e il Launcher di Minecraft prima di avviare l&#39;installer.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Potresti ricevere un avviso da Apple che il <code>.jar</code> non è verificato. Per raggirarlo, apri le Impostazioni di Sistema &gt; Privacy e Sicurezza, poi clicca <code>Apri comunque</code>. Conferma inserendo la tua password di amministratore se richiesta.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="Impostazioni di Sistema macOS" loading="lazy"></p></div><p>Una volta aperto l&#39;installer, dovresti vedere una schermata come questa:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer con &quot;Installa&quot; evidenziato" loading="lazy"></p><p>Scegli la versione di Minecraft desiderata e clicca <code>Installa</code>. Assicurati che <code>Crea Profilo</code> sia selezionato.</p><h3 id="installing-via-homebrew" tabindex="-1">Installa tramite Homebrew <a class="header-anchor" href="#installing-via-homebrew" aria-label="Permalink to “Installa tramite Homebrew”">​</a></h3><p>Se hai già installato <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>, puoi alternativamente usare <code>brew</code> per installare l&#39;Installer di Fabric:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fabric-installer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-finish-setup" tabindex="-1">3. Completa la Configurazione <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Completa la Configurazione”">​</a></h2><p>Appena l&#39;installazione è completata, apri il Launcher di Minecraft. Poi seleziona il profilo Fabric dal menu a tendina delle versioni, e clicca Gioca.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher di Minecraft con il profilo Fabric selezionato" loading="lazy"></p><p>Ora puoi aggiungere mod al gioco. Da&#39; un occhiata alla guida <a href="./finding-mods">Trovare Mod Affidabili</a> per maggiori informazioni.</p><p>Se incontri dei problemi, sentiti libero di chiedere aiuto nel server <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> nel canale <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};